# ── Historial ────────────────────────────────────────────────────
def cargar_historial():
    if os.path.exists(HISTORIAL_FILE):
        try:
            with open(HISTORIAL_FILE, "r", encoding="utf-8") as f:
                return json.load(f)
        except:
            pass
    return []

def guardar_historial(h):
    try:
        with open(HISTORIAL_FILE, "w", encoding="utf-8") as f:
            json.dump(h, f, ensure_ascii=False, indent=2)
    except:
        pass

# ── Análisis de imagen ───────────────────────────────────────────
def analizar_imagen(imagen_bytes, ext="jpg"):
    b64 = base64.b64encode(imagen_bytes).decode("utf-8")
    media_map = {"jpg":"image/jpeg","jpeg":"image/jpeg","png":"image/png","webp":"image/webp"}
    media_type = media_map.get(ext.lower(), "image/jpeg")

    prompt = """Eres FalconVet, un veterinario experto en ganado bovino de Colombia (cebu, brahman, angus, etc.).

Comienza tu respuesta SIEMPRE con: "Segun el analisis realizado, se ha observado lo siguiente:"

1. CONDICION CORPORAL: esta flaca, normal u obesa? (1 linea simple)
2. POSTURA: se ve bien parada o tiene algo raro? (1 linea simple)
3. CABEZA: ojos y nariz se ven bien o hay algo extrano? (1 linea simple)
4. PELAJE: se ve sano o tiene zonas raras? (1 linea simple)
5. ACTITUD: se ve activa o decaida? (1 linea simple)
6. DIAGNOSTICO: en palabras simples, que podria tener?
7. RECOMENDACIONES: maximo 2 cosas concretas para el ganadero.

Usa palabras simples que entienda cualquier ganadero colombiano.
IMPORTANTE: Solo di PRECAUCION o URGENTE si hay sintomas MUY claros.
En la ultima linea escribe EXACTAMENTE una de estas palabras: NORMAL | PRECAUCION | URGENTE"""

    payload = json.dumps({
        "model": "openrouter/auto",
        "messages": [{"role": "user", "content": [
            {"type": "text", "text": prompt},
            {"type": "image_url", "image_url": {"url": f"data:{media_type};base64,{b64}"}}
        ]}],
        "max_tokens": 1000
    }).encode("utf-8")

    req = urllib.request.Request(
        "https://openrouter.ai/api/v1/chat/completions",
        data=payload,
        headers={
            "Content-Type": "application/json",
            "Authorization": f"Bearer {API_KEY}",
            "HTTP-Referer": "https://falconvet.app",
            "X-Title": "FalconVet"
        },
        method="POST"
    )
    with urllib.request.urlopen(req, timeout=60) as resp:
        result = json.loads(resp.read().decode("utf-8"))
    return result["choices"][0]["message"]["content"]


def analizar_complementario(imagen_bytes, ext, resultado_foto, respuestas):
    b64 = base64.b64encode(imagen_bytes).decode("utf-8")
    media_map = {"jpg":"image/jpeg","jpeg":"image/jpeg","png":"image/png","webp":"image/webp"}
    media_type = media_map.get(ext.lower(), "image/jpeg")
    info = "\n".join([f"  - {k}: {v}" for k,v in respuestas.items()])

    prompt = f"""Eres FalconVet, veterinario experto en ganado bovino de Colombia.

Analisis fotografico previo:
---
{resultado_foto}
---

Informacion del ganadero:
{info}

Con TODA esta informacion, da un DIAGNOSTICO COMPLEMENTARIO:

Comienza con: "DIAGNOSTICO COMPLEMENTARIO (foto + informacion del ganadero):"

1. CONDICION CORPORAL: (1 linea)
2. POSTURA Y MOVILIDAD: (1 linea)
3. CABEZA: (1 linea)
4. PELAJE: (1 linea)
5. SENALES CLINICAS REPORTADAS: resume lo importante
6. DIAGNOSTICO ACTUALIZADO: se mas especifico
7. URGENCIA: debe llamar al veterinario HOY, esta semana, o puede esperar?
8. ACCIONES INMEDIATAS: maximo 3 pasos concretos

En la ultima linea: NORMAL | PRECAUCION | URGENTE"""

    payload = json.dumps({
        "model": "openrouter/auto",
        "messages": [{"role": "user", "content": [
            {"type": "text", "text": prompt},
            {"type": "image_url", "image_url": {"url": f"data:{media_type};base64,{b64}"}}
        ]}],
        "max_tokens": 1200
    }).encode("utf-8")

    req = urllib.request.Request(
        "https://openrouter.ai/api/v1/chat/completions",
        data=payload,
        headers={
            "Content-Type": "application/json",
            "Authorization": f"Bearer {API_KEY}",
            "HTTP-Referer": "https://falconvet.app",
            "X-Title": "FalconVet"
        },
        method="POST"
    )
    with urllib.request.urlopen(req, timeout=60) as resp:
        result = json.loads(resp.read().decode("utf-8"))
    return result["choices"][0]["message"]["content"]


def detectar_estado(texto):
    ultima = texto.strip().split("\n")[-1].upper()
    if "URGENTE" in ultima:
        return "URGENTE"
    elif "PRECAUCION" in ultima or "PRECAUCIÓN" in ultima:
        return "PRECAUCION"
    return "NORMAL"


def render_resultado(texto):
    if not texto:
        return ""
    palabras_titulo = ["CONDICION","POSTURA","CABEZA","PELAJE","VIENTRE","ACTITUD",
                       "DIAGNOSTICO","RECOMENDACIONES","SENALES","URGENCIA","ACCIONES",
                       "COMPLEMENTARIO"]
    lines = texto.split("\n")
    html = '<div class="result-box">'
    for linea in lines:
        upper = linea.upper()
        if any(p in upper for p in palabras_titulo):
            html += f'<span class="titulo">{linea}</span>\n'
        elif "URGENTE" in upper:
            html += f'<span class="urgente">{linea}</span>\n'
        elif "PRECAUCION" in upper or "PRECAUCIÓN" in upper:
            html += f'<span class="precau">{linea}</span>\n'
        elif "NORMAL" in upper and len(linea.strip()) < 20:
            html += f'<span class="normal">{linea}</span>\n'
        else:
            html += linea + "\n"
    html += "</div>"
    return html


